   192→  result.explainabilityTrace.multiLabelSelection = multiLabelResults;
   193→  result.explainabilityTrace.stageTimings['multiLabelSelection'] = duration;
   194→  result.explainabilityTrace.configurationRefs['multiLabelSelection'] = 'settings.multiLabelSelection';
   195→}
