   197→/**
   198→ * Validate configuration parameters
   199→ */
   200→function validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
   201→  if (config.maxLabels < 0) {
   202→    throw new Error('Invalid configuration: maxLabels cannot be negative');
   203→  }
   204→
   205→  if (config.minSecondaryConfidence < 0) {
   206→    throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
   207→  }
   208→
   209→  if (thresholds.highConfidence <= thresholds.mediumConfidence) {
   210→    throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
   211→  }
   212→
   213→  if (thresholds.mediumConfidence <= thresholds.lowConfidence) {
   214→    throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
   215→  }
   216→
   217→  if (thresholds.secondaryLabelMinGap < 0) {
   218→    throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
   219→  }
   220→}
   221→
   222→/**
   223→ * Rank categories by score in descending order, filtering out zero/negative scores
   224→ */
   225→function rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
   226→  category: string;
   227→  score: number;
   228→  confidence: number;
   229→  rationale: string;
   230→  selectedSubtypeId?: string | null;
   231→}> {
   232→  return Object.entries(candidateScores)
   233→    .map(([category, scoreData]) => ({
   234→      category,
   235→      score: scoreData.score || 0,
   236→      confidence: scoreData.confidence || 0,
   237→      rationale: scoreData.rationale || '',
   238→      selectedSubtypeId: scoreData.selectedSubtypeId,
   239→    }))
   240→    .filter((item) => item.score > 0)
   241→    .sort((a, b) => {
   242→      // Primary sort by score (descending)
   243→      if (b.score !== a.score) {
   244→        return b.score - a.score;
   245→      }
   246→      // Secondary sort by category name for stable ordering
   247→      return a.category.localeCompare(b.category);
   248→    });
   249→}
   250→
   251→/**
   252→ * Select secondary labels within gap threshold and above minimum confidence
   253→ */
   254→function selectSecondaryLabels(
   255→  rankedCategories: Array<{
   256→    category: string;
   257→    score: number;
   258→    confidence: number;
   259→    rationale: string;
   260→    selectedSubtypeId?: string | null;
   261→  }>,
   262→  selectedLabels: SelectedLabel[],
   263→  primaryCandidate: {
   264→    category: string;
   265→    score: number;
   266→    confidence: number;
   267→    rationale: string;
   268→    selectedSubtypeId?: string | null;
   269→  },
   270→  config: MultiLabelConfig,
   271→  thresholds: ConfidenceThresholds
   272→): void {
   273→  if (config.maxLabels <= 1 || rankedCategories.length <= 1) {
   274→    return;
   275→  }
   276→
   277→  const primaryScore = primaryCandidate.score;
   278→
   279→  for (let i = 1; i < rankedCategories.length && selectedLabels.length < config.maxLabels; i++) {
   280→    const candidate = rankedCategories[i];
   281→    const scoreDifference = primaryScore - candidate.score;
   282→
   283→    // Check if candidate meets secondary label criteria
   284→    if (candidate.score >= config.minSecondaryConfidence && scoreDifference <= thresholds.secondaryLabelMinGap) {
   285→      // Check if combination is allowed
   286→      if (isCombinationAllowed(primaryCandidate.category, candidate.category, config)) {
   287→        const secondaryLabel: SelectedLabel = {
   288→          category: candidate.category,
   289→          subtype: candidate.selectedSubtypeId || null,
   290→          confidence: candidate.confidence,
   291→          score: candidate.score,
   292→          isPrimary: false,
   293→          labelOrder: selectedLabels.length + 1,
   294→          selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${thresholds.secondaryLabelMinGap}) and above minimum confidence (${config.minSecondaryConfidence})`,
   295→        };
   296→        selectedLabels.push(secondaryLabel);
   297→      }
   298→    }
   299→  }
   300→}
   301→
   302→/**
   303→ * Check if category combination is allowed based on configuration
   304→ */
   305→function isCombinationAllowed(primaryCategory: string, candidateCategory: string, config: MultiLabelConfig): boolean {
   306→  if (primaryCategory === candidateCategory) {
   307→    return true;
   308→  }
   309→
   310→  // If strict mode is enabled and combinations are specified, only allow explicit combinations
   311→  if (config.strictCombinationMode && config.allowedCombinations.length > 0) {
   312→    return config.allowedCombinations.some((combo) => {
   313→      const categories = combo.categories;
   314→      return categories && categories.includes(primaryCategory) && categories.includes(candidateCategory);
   315→    });
   316→  }
   317→
   318→  // If no combinations specified, allow all (default permissive mode)
   319→  if (config.allowedCombinations.length === 0) {
   320→    return true;
   321→  }
   322→
   323→  // If combinations are specified but not in strict mode, still check them
   324→  const isExplicitlyAllowed = config.allowedCombinations.some((combo) => {
   325→    const categories = combo.categories;
   326→    return categories && categories.includes(primaryCategory) && categories.includes(candidateCategory);
   327→  });
   328→
   329→  // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
   330→  return isExplicitlyAllowed || !config.strictCombinationMode;
   331→}
   332→
   333→/**
   334→ * Update category decisions based on selection results
   335→ */
   336→function updateCategoryDecisions(
   337→  candidateScores: Record<string, CategoryScore>,
   338→  selectedLabels: SelectedLabel[],
   339→  thresholds: ConfidenceThresholds
   340→): void {
   341→  const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));
   342→
   343→  for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
   344→    const score = scoreData.score || 0;
   345→
   346→    if (selectedCategoryNames.has(categoryCode)) {
   347→      // Selected categories get decision based on confidence
   348→      if (score >= thresholds.highConfidence) {
   349→        scoreData.decision = 'selected';
   350→        scoreData.decisionRationale = `High confidence (${score} >= ${thresholds.highConfidence}) - finalized without AI`;
   351→      } else if (score >= thresholds.mediumConfidence) {
   352→        scoreData.decision = 'candidate';
   353→        scoreData.decisionRationale = `Medium confidence (${score} >= ${thresholds.mediumConfidence}) - may need AI validation`;
   354→      } else {
   355→        scoreData.decision = 'candidate';
   356→        scoreData.decisionRationale = `Low confidence (${score} >= ${thresholds.lowConfidence}) - needs AI classification`;
   357→      }
   358→    } else {
   359→      // Non-selected categories are rejected
   360→      scoreData.decision = 'rejected';
   361→      if (score < thresholds.lowConfidence) {
   362→        scoreData.decisionRationale = `Below minimum threshold (${score} < ${thresholds.lowConfidence})`;
   363→      } else {
   364→        scoreData.decisionRationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
   365→      }
   366→    }
   367→  }
   368→}
   369→
   370→/**
   371→ * Determine if AI classification is needed based on selected labels
   372→ */
   373→function determineAiClassificationNeed(selectedLabels: SelectedLabel[], thresholds: ConfidenceThresholds): boolean {
   374→  if (selectedLabels.length === 0) {
   375→    return true; // No labels selected - need AI
   376→  }
   377→
   378→  // Check if primary label has high confidence (can skip AI)
   379→  const primaryLabel = selectedLabels.find((label) => label.isPrimary);
   380→  if (primaryLabel && primaryLabel.score >= thresholds.highConfidence) {
   381→    return false; // High confidence primary - skip AI
   382→  }
   383→
   384→  // Check if any label is below medium confidence (needs AI)
   385→  const hasLowConfidenceLabel = selectedLabels.some((label) => label.score < thresholds.mediumConfidence);
   386→  if (hasLowConfidenceLabel) {
   387→    return true; // Has low confidence labels - need AI
   388→  }
   389→
   390→  // Conservative approach for medium confidence range
   391→  return true;
   392→}
