import { z } from 'zod';
import type {
  CategoryRuleResult,
  ClassificationResult,
  ClassificationSession,
  EmailMessage,
  RuleScoringMatch,
  SubtypeDefinition,
  SubtypeScore,
  TopLevelCategory,
} from '../types';
import { RulePatternSchema } from '../config/category-config-schema';
import { ensureCategoryScoreInitialized } from '../utils/initialization';
import { matchRulePattern } from '../utils/rule-matcher';

/**
 * Rule-Based Scoring Stage
 *
 * Implements lexical pattern matching per SCORING_LOGIC.md "Subtype Scoring Formula" section.
 * Applies rule-based classification patterns with bounded aggregation to prevent score inflation
 * while allowing multiple patterns to contribute to category confidence.
 *
 * CANONICAL SIGNATURE: (email, session, result, config) => void
 *
 * Logic (per SCORING_LOGIC.md):
 * - score(subtype) = sum(high_match_weights) * KHigh
 *                  + sum(medium_match_weights) * KMedium
 *                  + sum(low_match_weights) * KLow
 * - K parameters are MULTIPLIERS applied to sum of ALL tier weights (not topK limits)
 * - Category score = primary + min(secondarySupport, secondarySupportCap)
 * - Uses max of existing score vs aggregated rule score
 * - Mutates result.explainabilityTrace and result.scoreBreakdown instead of returning
 */

export type SubtypeRuleClassification = NonNullable<SubtypeDefinition['ruleBasedClassification']>;

export interface RuleScoringStageConfig {
  // Configuration settings for rule scoring behavior
  settings: {
    useLexicalPatterns: boolean;
    applySubtypeRules: boolean;
    boundedAggregation: boolean;
  };

  // Top-level categories with their subtypes and rules
  topLevelCategories: Record<string, TopLevelCategory>;

  // Tuning parameters for subtype scoring formula
  tuningParameters: {
    KHigh: number; // Multiplier for sum of high-confidence match weights
    KMedium: number; // Multiplier for sum of medium-confidence match weights
    KLow: number; // Multiplier for sum of low-confidence match weights
    TAIL_DAMPEN: number; // Damping factor for secondary subtype support
    TAIL_RATIO_CAP: number; // Max ratio of tail support to primary score
    aggregationCap: number; // Maximum score a category can reach from rule aggregation (default: 1.0)
  };
}

// Type re-exports for convenience (actual definitions in types/explainability-trace.ts)
export type { CategoryRuleResult, RuleScoringMatch, SubtypeScore };

export interface RuleScoringResult {
  categoryResults: CategoryRuleResult[];
  updatedScores: Record<string, number>;
  totalMatches: number;
  categoriesWithRules: number;
  highestRuleScore: number;
  processingDurationMs: number;
}

export const SubtypeRuleClassificationSchema = z.object({
  highConfidence: z.array(RulePatternSchema).optional(),
  mediumConfidence: z.array(RulePatternSchema).optional(),
  lowConfidence: z.array(RulePatternSchema).optional(),
});

export const RuleScoringStageConfigSchema = z.object({
  settings: z.object({
    useLexicalPatterns: z.boolean(),
    applySubtypeRules: z.boolean(),
    boundedAggregation: z.boolean(),
  }),
  topLevelCategories: z.record(
    z.object({
      description: z.string(),
      subtypes: z.record(
        z.object({
          description: z.string(),
          ruleBasedClassification: SubtypeRuleClassificationSchema.optional(),
          derived: z.boolean().optional(),
          derivationLogic: z.string().optional(),
        })
      ),
    })
  ),
  tuningParameters: z.object({
    KHigh: z.number().min(0), // Allow fractional multipliers (e.g., 1.0, 0.7)
    KMedium: z.number().min(0), // Allow fractional multipliers
    KLow: z.number().min(0), // Allow fractional multipliers
    TAIL_DAMPEN: z.number().min(0).max(1),
    TAIL_RATIO_CAP: z.number().min(0).max(1),
    aggregationCap: z.number().min(0).default(1.0), // Maximum score from rule aggregation
  }),
});

/**
 * Execute rule-based scoring stage
 *
 * @param email - Email message to analyze for pattern matches
 * @param session - Classification session batch metadata (canonical signature parameter, not used directly)
 * @param result - Classification result to update (mutated in place)
 * @param config - Rule scoring configuration with pattern hierarchies
 */
export function executeRuleScoring(
  email: EmailMessage,
  _session: ClassificationSession,
  result: ClassificationResult,
  config: RuleScoringStageConfig
): void {
  const startTime = Date.now();

  console.log(`Rule scoring for email ${email.id}: "${email.subject?.substring(0, 50)}..."`);

  const { settings, topLevelCategories, tuningParameters } = config;

  // Early exit if rule scoring is disabled
  if (!settings.useLexicalPatterns || !settings.applySubtypeRules) {
    console.log('Rule scoring disabled by configuration');
    const durationMs = Date.now() - startTime;
    result.explainabilityTrace.stageTimings['ruleScoring'] = durationMs;
    result.explainabilityTrace.configurationRefs['ruleScoring'] =
      'config.processingConfig.topLevelCategories.*.subtypes.*.ruleBasedClassification';
    result.processingDurationMs += durationMs;
    return;
  }

  const categoryResults: CategoryRuleResult[] = [];

  console.log(`Found ${Object.keys(topLevelCategories).length} top-level categories to process`);

  // Process each top-level category
  for (const [categoryCode, categoryData] of Object.entries(topLevelCategories)) {
    console.log(
      `Processing category '${categoryCode}' with ${Object.keys(categoryData.subtypes || {}).length} subtypes`
    );

    const subtypeScores: Record<string, SubtypeScore> = {};
    const categoryRuleMatches: RuleScoringMatch[] = [];
    const categoryRationale: string[] = [];

    // Process subtypes for this category
    if (categoryData.subtypes) {
      for (const [subtypeCode, subtypeData] of Object.entries(categoryData.subtypes)) {
        const subtypeScore = scoreSubtype(email, subtypeData, subtypeCode, tuningParameters);

        if (subtypeScore.totalScore > 0) {
          subtypeScores[subtypeCode] = subtypeScore;
          categoryRuleMatches.push(...subtypeScore.ruleMatches);
          console.log(
            `Subtype '${subtypeCode}' scored ${subtypeScore.totalScore} with ${subtypeScore.ruleMatches.length} matches`
          );
        }
      }
    }

    // Calculate aggregated category score using bounded aggregation
    let categoryScore = result.scoreBreakdown.categoryScores[categoryCode]?.finalScore || 0; // Start with existing score

    if (settings.boundedAggregation && Object.keys(subtypeScores).length > 0) {
      const aggregatedScore = calculateBoundedAggregation(subtypeScores, tuningParameters);

      // Use max of existing score vs aggregated rule score
      categoryScore = Math.max(categoryScore, aggregatedScore.totalScore);

      // Apply aggregationCap to prevent score inflation (per SCORING_LOGIC.md line 52)
      const uncappedScore = categoryScore;
      categoryScore = Math.min(categoryScore, tuningParameters.aggregationCap);

      categoryRationale.push(`Rule aggregation: ${aggregatedScore.breakdown}`);
      if (uncappedScore > tuningParameters.aggregationCap) {
        categoryRationale.push(`Applied aggregationCap: ${uncappedScore.toFixed(2)} → ${categoryScore.toFixed(2)}`);
        console.log(
          `Category '${categoryCode}' rule score capped: ${uncappedScore.toFixed(2)} → ${categoryScore.toFixed(2)} (cap: ${tuningParameters.aggregationCap})`
        );
      } else {
        console.log(
          `Category '${categoryCode}' rule score: ${aggregatedScore.totalScore} (${aggregatedScore.breakdown})`
        );
      }
    }

    // Calculate confidence based on score and number of matches
    const confidence = calculateConfidence(categoryScore, categoryRuleMatches.length, tuningParameters.aggregationCap);

    // Select best subtype
    const selectedSubtypeId = selectBestSubtype(subtypeScores);

    // Create category result
    const categoryResult: CategoryRuleResult = {
      categoryCode,
      aggregatedScore: categoryScore,
      subtypeScores,
      ruleMatches: categoryRuleMatches,
      scoringRationale:
        categoryRationale.length > 0
          ? categoryRationale
          : [`Rule-based classification: ${categoryScore} points from ${categoryRuleMatches.length} matches`],
      selectedSubtypeId,
      confidence,
    };

    categoryResults.push(categoryResult);

    // Ensure category score is initialized using canonical helper
    ensureCategoryScoreInitialized(result, categoryCode);

    result.scoreBreakdown.categoryScores[categoryCode].ruleScore = categoryScore;
    result.scoreBreakdown.categoryScores[categoryCode].finalScore = categoryScore;
  }

  // Calculate summary metrics
  const totalMatches = categoryResults.reduce((sum, result) => sum + result.ruleMatches.length, 0);
  const categoriesWithRules = categoryResults.filter((result) => Object.keys(result.subtypeScores).length > 0).length;

  console.log(`Rule scoring complete - ${totalMatches} matches across ${categoriesWithRules} categories`);

  // Update result.explainabilityTrace with rule scoring results
  // Store CategoryRuleResult[] directly for better explainability
  result.explainabilityTrace.ruleScoring = categoryResults;

  // Track stage timing
  const durationMs = Date.now() - startTime;
  result.explainabilityTrace.stageTimings['ruleScoring'] = durationMs;
  result.explainabilityTrace.configurationRefs['ruleScoring'] =
    'config.processingConfig.topLevelCategories.*.subtypes.*.ruleBasedClassification';
  result.processingDurationMs += durationMs;
}

/**
 * Score a single subtype based on its rule-based classification patterns
 *
 * Per SCORING_LOGIC.md:
 * score(subtype) = sum(high_match_weights) * KHigh
 *                + sum(medium_match_weights) * KMedium
 *                + sum(low_match_weights) * KLow
 */
function scoreSubtype(
  email: EmailMessage,
  subtypeData: SubtypeDefinition,
  subtypeCode: string,
  tuningParams: RuleScoringStageConfig['tuningParameters']
): SubtypeScore {
  const ruleClassification = subtypeData.ruleBasedClassification || {};
  const matches: RuleScoringMatch[] = [];

  // Process each confidence tier: sum ALL matches, then multiply by K
  const confidenceTiers: Array<{
    tier: keyof SubtypeRuleClassification;
    multiplier: number; // K parameter (multiplier applied to sum of weights)
  }> = [
    { tier: 'highConfidence', multiplier: tuningParams.KHigh },
    { tier: 'mediumConfidence', multiplier: tuningParams.KMedium },
    { tier: 'lowConfidence', multiplier: tuningParams.KLow },
  ];

  let totalScore = 0;
  const tierBreakdowns: string[] = [];

  for (const { tier, multiplier } of confidenceTiers) {
    const tierRules = ruleClassification[tier] || [];
    const tierMatches: RuleScoringMatch[] = [];
    let tierWeightSum = 0;

    for (const rule of tierRules) {
      const match = matchRulePattern(email, rule);

      if (match.matched) {
        tierMatches.push({
          tier,
          field: rule.field,
          operation: rule.operation,
          values: rule.values || [],
          weight: rule.weight,
          matchedValue: match.matchedValue,
          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
          ruleWeight: rule.weight, // For compatibility with RuleMatch base interface
          partialMatch: false, // For compatibility with RuleMatch base interface
        });

        tierWeightSum += rule.weight;
        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
      }
    }

    // Apply K multiplier to sum of ALL tier weights (not topK limit)
    if (tierWeightSum > 0) {
      const tierScore = tierWeightSum * multiplier;
      totalScore += tierScore;
      tierBreakdowns.push(`${tier}:sum(${tierWeightSum})*${multiplier}=${tierScore.toFixed(2)}`);

      // Add all matches to the result (not just topK)
      matches.push(...tierMatches);
    }
  }

  return {
    totalScore,
    ruleMatches: matches,
    aggregationBreakdown: tierBreakdowns.length > 0 ? tierBreakdowns.join(' + ') : 'noMatches',
  };
}

/**
 * Calculate bounded aggregation score to prevent inflation
 * Uses diminishing returns: primary subtype + dampened tail support
 */
function calculateBoundedAggregation(
  subtypeScores: Record<string, SubtypeScore>,
  tuningParams: RuleScoringStageConfig['tuningParameters']
): { totalScore: number; breakdown: string } {
  const scores = Object.entries(subtypeScores)
    .map(([subtype, data]) => ({ subtype, score: data.totalScore }))
    .sort((a, b) => b.score - a.score); // Sort by score descending

  if (scores.length === 0) {
    return { totalScore: 0, breakdown: 'noSubtypes' };
  }

  // Primary subtype (highest score) contributes fully
  const primaryScore = scores[0].score;
  const primarySubtype = scores[0].subtype;

  // Tail support: additional subtypes contribute with diminishing returns
  let tailSupport = 0;
  const tailContributions: string[] = [];

  if (scores.length > 1) {
    const tailScores = scores.slice(1);

    for (const tail of tailScores) {
      const contribution = tail.score * tuningParams.TAIL_DAMPEN;
      tailSupport += contribution;
      tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
    }

    // Apply tail ratio cap
    const maxTailSupport = primaryScore * tuningParams.TAIL_RATIO_CAP;
    tailSupport = Math.min(tailSupport, maxTailSupport);
  }

  const totalScore = primaryScore + tailSupport;
  const breakdown =
    `primary:${primarySubtype}:${primaryScore}` +
    (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');

  return { totalScore, breakdown };
}

/**
 * Calculate confidence percentage based on score and number of matches
 *
 * Normalizes scores using aggregationCap to handle raw weighted scores (which can be >> 1)
 * after T064 K parameter semantics fix.
 *
 * @param score - Raw category score (can be 0-150+ depending on rule weights and K multipliers)
 * @param numMatches - Number of rule matches
 * @param aggregationCap - Maximum expected score (used for normalization)
 * @returns Confidence percentage (0-95)
 */
function calculateConfidence(score: number, numMatches: number, aggregationCap: number): number {
  if (score === 0) return 0;

  // Normalize score to 0-1 range using aggregationCap as the expected maximum
  // If aggregationCap is 1.0 and score is 63, normalized = min(63/1.0, 1.0) = 1.0
  // If aggregationCap is 100 and score is 63, normalized = min(63/100, 1.0) = 0.63
  const normalizedScore = Math.min(score / aggregationCap, 1.0);

  // Basic confidence calculation: higher scores and more matches = higher confidence
  // Cap at 95% to leave room for AI enhancement
  const baseConfidence = normalizedScore * 80; // 0-80% from normalized score
  const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%

  return Math.min(baseConfidence + matchBonus, 95);
}

/**
 * Select the best subtype based on scores
 */
function selectBestSubtype(subtypeScores: Record<string, SubtypeScore>): string | null {
  if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
    return null;
  }

  // Find subtype with highest score
  let bestSubtype: string | null = null;
  let bestScore = -1;

  for (const [subtypeId, scoreData] of Object.entries(subtypeScores)) {
    const score = scoreData?.totalScore || 0;
    if (score > bestScore) {
      bestScore = score;
      bestSubtype = subtypeId;
    }
  }

  return bestScore > 0 ? bestSubtype : null;
}

