/**
 * ScoreBreakdown entity with parallel computation tracking
 *
 * Detailed score calculation with parallel processing context,
 * implementing category score aggregation per SCORING_LOGIC.md.
 */

export interface ScoreBreakdown {
  emailId: string;

  // Category scores (preserved structure from SCORING_LOGIC.md)
  categoryScores: Record<string, CategoryScoreDetails>;

  // Stage contributions with parallel processing metadata
  stageContributions: Record<string, StageContribution>;

  // Disambiguation tracking
  disambiguationApplied: DisambiguationApplication[];

  // Parallel processing optimization data
  parallelComputationMetrics: ParallelComputationMetrics;
}

/**
 * Category score details implementing the Category Score section
 * from SCORING_LOGIC.md with enhanced parallel processing tracking
 */
export interface CategoryScoreDetails {
  baseScore: number;
  hardAssertionBonus: number;
  strongIndicatorScore: number;
  ruleScore: number;
  attributeInfluenceScore: number;
  finalScore: number;

  // Enhanced breakdown for parallel processing
  parallelComputedComponents: string[]; // Which parts computed in parallel
  computationDurationMs: number;
  cacheHits: string[]; // Which calculations used cached results

  // Score aggregation tracking
  scoreAggregationSteps: ScoreAggregationStep[];
  cappingApplied: boolean;
  cappingReason?: string;
}

/**
 * Individual score aggregation step for detailed audit trail
 */
export interface ScoreAggregationStep {
  stepNumber: number;
  operation: 'seed' | 'addRuleScore' | 'applyAttributeBonus' | 'applyCap' | 'disambiguationAdjustment';
  scoreBefore: number;
  scoreAfter: number;
  contribution: number;
  source: string; // Which stage/rule/attribute contributed this
  reason: string;
  timestamp: Date;
}

/**
 * Stage contribution with parallel processing dependencies
 */
export interface StageContribution {
  contribution: number;
  confidence: number;
  processingMode: 'parallel' | 'sequential';
  dependencies: string[]; // Other stages this depended on

  // Performance tracking
  executionTimeMs: number;
  memoryUsageMB?: number;
  cacheUtilization: CacheUtilization;

  // Quality metrics
  contributionReliability: number; // How reliable this stage's contribution is
  contributionConsistency: number; // How consistent with past similar emails
}

export interface CacheUtilization {
  cacheHits: number;
  cacheMisses: number;
  cacheHitRate: number;
  cachedResults: string[]; // What was retrieved from cache
}

/**
 * Disambiguation application tracking
 */
export interface DisambiguationApplication {
  categories: string[];
  rule: string;
  scoreAdjustment: number;
  reason: string;

  // Parallel processing context
  appliedDuringParallelExecution: boolean;
  dependentOnParallelResults: string[];
  adjustmentTimestamp: Date;
}

/**
 * Parallel computation metrics for performance optimization
 */
export interface ParallelComputationMetrics {
  totalParallelOperations: number;
  parallelEfficiencyScore: number; // How well parallel processing was utilized
  bottleneckStages: string[]; // Stages that limited parallel performance

  // Resource utilization
  peakMemoryUsageMB: number;
  averageCpuUtilization: number;
  concurrentOperationsPeak: number;

  // Optimization opportunities
  parallelizableButSequential: string[]; // Operations that could be parallelized
  parallelConflicts: ParallelConflict[]; // Where parallel processing caused issues
}

export interface ParallelConflict {
  conflictType: 'resourceContention' | 'dataDependency' | 'cacheInvalidation';
  involvedStages: string[];
  performanceImpact: number; // Milliseconds lost due to conflict
  resolution: string;
  mitigationSuggestion?: string;
}

/**
 * Enhanced score breakdown for debugging and optimization
 */
export interface DetailedScoreBreakdown extends ScoreBreakdown {
  // Additional analysis for score debugging
  scoreDistribution: {
    [category: string]: {
      percentileRank: number; // Where this score ranks among similar emails
      historicalAverage: number;
      standardDeviation: number;
      confidenceInterval: [number, number];
    };
  };

  // Cross-category analysis
  categoryCorrelations: {
    [categoryPair: string]: number; // Correlation between category scores
  };

  // Configuration impact analysis
  configurationSensitivity: {
    [parameter: string]: {
      currentValue: unknown;
      scoreImpact: number; // How much this parameter affected final scores
      sensitivity: 'low' | 'medium' | 'high';
    };
  };
}

/**
 * Score calculation formulas implementing SCORING_LOGIC.md requirements
 */
export interface ScoreCalculationFormulas {
  // Subtype scoring formula with K parameters
  subtypeScoring: {
    KHigh: number;
    KMedium: number;
    KLow: number;
    formula: string; // "sum(ruleWeights * K_tier) capped at 1.0"
  };

  // Diminishing returns formula for strong indicators
  diminishingReturns: {
    formula: string; // "newScore = existing + (newContribution * (1 - existing))"
    maxAccumulation: number;
  };

  // Attribute bonus calculations
  attributeBonus: {
    coreBonusMultiplier: number;
    primaryBoostMultiplier: number;
    secondaryBoostMultiplier: number;
    maxBonusPerCategory: number;
  };
}

